<?php
 namespace WPAICG\Chat\Frontend\Shortcode; use WPAICG\Chat\Storage\SiteWideBotManager; use WPAICG\Chat\Frontend\Shortcode; if (!defined('ABSPATH')) { exit; } class SiteWideHandler { private $site_wide_manager; private $shortcode_instance; private static $site_wide_bot_id_cache = null; public function __construct(Shortcode $shortcode_instance) { $this->site_wide_manager = new SiteWideBotManager(); $this->shortcode_instance = $shortcode_instance; } public function inject_site_wide_chatbot() { if (is_admin() || wp_doing_ajax()) return; if (self::$site_wide_bot_id_cache === null) { self::$site_wide_bot_id_cache = $this->site_wide_manager->get_site_wide_bot_id(); } $bot_id_to_inject = self::$site_wide_bot_id_cache; if ($this->shortcode_instance && $bot_id_to_inject) { if (!isset($this->shortcode_instance::$rendered_bot_ids[$bot_id_to_inject])) { echo $this->shortcode_instance->render_chatbot_shortcode(['id' => $bot_id_to_inject]); } } } }